import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Einführung in Fabric und Modding","description":"Eine kurze Einführung in Fabric und Modding in Minecraft: Java Edition.","frontmatter":{"title":"Einführung in Fabric und Modding","description":"Eine kurze Einführung in Fabric und Modding in Minecraft: Java Edition.","authors":["IMB11","itsmiir"],"authors-nogithub":["basil4088"],"files":[]},"headers":[],"relativePath":"de_de/1.21.10/develop/getting-started/introduction-to-fabric-and-modding.md","filePath":"versions/1.21.10/translated/de_de/develop/getting-started/introduction-to-fabric-and-modding.md","lastUpdated":1766682904000}`);var a={name:`de_de/1.21.10/develop/getting-started/introduction-to-fabric-and-modding.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Einführung in Fabric und Modding <a class="header-anchor" href="#h1" aria-label="Permalink to “Einführung in Fabric und Modding”">​</a></h1><h2 id="prerequisites" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Voraussetzungen”">​</a></h2><p>Bevor du anfängst, solltest du ein Grundverständnis für die Entwicklung mit Java und ein Verständnis für objektorientierte Programmierung (OOP) haben.</p><p>Wenn du mit diesen Konzepten nicht vertraut bist, solltest du dir einige Tutorials zu Java und OOP ansehen, bevor du mit dem Modding beginnst. Hier sind einige der Ressourcen, die du nutzen kannst, um Java und OOP zu lernen:</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Java Tutorials</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Java lernen</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: Einführung in die OOP</a></li></ul><h3 id="terminology" tabindex="-1">Begriffserklärung <a class="header-anchor" href="#terminology" aria-label="Permalink to “Begriffserklärung”">​</a></h3><p>Bevor wir beginnen, wollen wir einige Begriffe erläutern, die bei der Arbeit mit Fabric vorkommen werden:</p><ul><li><strong>Mod</strong>: Eine Modifikation des Spiels, die neue Funktionen hinzufügt oder bestehende ändert.</li><li><strong>Mod-Loader</strong>: Ein Tool, das Mods in das Spiel lädt, wie zum Beispiel der Fabric Loader.</li><li><strong>Mixin</strong>: Ein Werkzeug zum Ändern des Spielcodes zur Laufzeit - siehe <a href="https://fabricmc.net/wiki/tutorial:mixin_introduction" target="_blank" rel="noreferrer">Mixin-Einführung</a> für weitere Informationen.</li><li><strong>Gradle</strong>: Ein Build-Automatisierungstool zum Erstellen und Kompilieren von Mods, das von Fabric zum Erstellen von Mods verwendet wird.</li><li><strong>Mappings</strong>: Eine Reihe von Mappings, die obfuskierten Code auf menschenlesbaren Code abbilden.</li><li><strong>Obfuskation</strong>: Der Prozess, der Code schwer verständlich macht und von Mojang verwendet wird, um den Code von Minecraft zu schützen.</li><li><strong>Remapping</strong>: Der Prozess der Umwandlung von obfuskierten Code in für Menschen lesbaren Code.</li></ul><h2 id="what-is-fabric" tabindex="-1">Was ist Fabric? <a class="header-anchor" href="#what-is-fabric" aria-label="Permalink to “Was ist Fabric?”">​</a></h2><p>Fabric ist eine leichtgewichtige Modding-Werkzeugbox für Minecraft: Java Edition.</p><p>Sie ist als einfache und leicht zu bedienende Modding-Plattform konzipiert. Fabric ist ein von der Gemeinschaft getragenes Projekt und ist Open Source, was bedeutet, dass jeder zu dem Projekt beitragen kann.</p><p>Du solltest die vier Hauptkomponenten von Fabric kennen:</p><ul><li><strong>Fabric Loader</strong>: Ein flexibler, plattformunabhängiger Mod-Loader für Minecraft und andere Spiele und Anwendungen.</li><li><strong>Fabric Loom</strong>: Ein Gradle-Plugin, das es Entwicklern ermöglicht, Mods einfach zu entwickeln und zu debuggen.</li><li><strong>Fabric API</strong>: Eine Reihe von APIs und Werkezuge für Mod-Entwickler, die du bei der Erstellung von Mods verwenden kannst.</li><li><strong>Yarn</strong>: Eine Reihe offener Minecraft-Mappings, die unter der Creative Commons Zero-Lizenz für jeden frei nutzbar sind.</li></ul><h2 id="why-is-fabric-necessary-to-mod-minecraft" tabindex="-1">Warum wird Fabric für das Modden von Minecraft benötigt? <a class="header-anchor" href="#why-is-fabric-necessary-to-mod-minecraft" aria-label="Permalink to “Warum wird Fabric für das Modden von Minecraft benötigt?”">​</a></h2><blockquote><p>Beim Modding wird ein Spiel modifiziert, um sein Verhalten zu ändern oder neue Funktionen hinzuzufügen - im Fall von Minecraft kann dies alles sein, vom Hinzufügen neuer Items, Blöcke oder Entitäten bis hin zur Änderung der Spielmechanik oder dem Hinzufügen neuer Spielmodi.</p></blockquote><p>Minecraft: Die Java Edition wird von Mojang obfuskiert, was Modifikationen allein schwierig macht. Mit Hilfe von Modding-Werkzeugen wie Fabric wird das Modding jedoch viel einfacher. Es gibt verschiedene Mapping-Systeme, die bei diesem Prozess helfen können.</p><p>Loom wandelt den obfuskierten Code mit Hilfe dieser Mappings in ein für Menschen lesbares Format um, was es Moddern erleichtert, den Code des Spiels zu verstehen und zu verändern. Yarn ist eine beliebte und ausgezeichnete Wahl für diese Mappings, aber es gibt auch andere Optionen. Jedes Mapping-Projekt kann seine eigenen Stärken oder Schwerpunkte haben.</p><p>Mit Loom kannst du auf einfache Weise Mods entwickeln und Mods gegen remapped Code kompilieren, und mit Fabric Loader kannst du diese Mods in das Spiel laden.</p><h2 id="what-does-fabric-api-provide-and-why-is-it-needed" tabindex="-1">Was bietet die Fabric API und warum ist sie nötig? <a class="header-anchor" href="#what-does-fabric-api-provide-and-why-is-it-needed" aria-label="Permalink to “Was bietet die Fabric API und warum ist sie nötig?”">​</a></h2><blockquote><p>Fabric API ist eine Sammlung von APIs und Werkzeugen, die Mod-Entwickler bei der Erstellung von Mods verwenden können.</p></blockquote><p>Die Fabric API bietet eine Vielzahl von APIs, die auf der bestehenden Funktionalität von Minecraft aufbauen - zum Beispiel neue Hooks und Events, die Modder nutzen können, oder neue Utilities und Werkzeuge, die das Modding vereinfachen - wie zum Beispiel Access Wideners und die Möglichkeit, auf interne Registrys zuzugreifen, wie zui, Beispiel die Registry für kompostierbare Items.</p><p>Während die Fabric API leistungsstarke Funktionen bietet, können einige Aufgaben, wie zum Beispiel die grundlegende Blockregistrierung, auch ohne sie mit den Vanilla APIs durchgeführt werden.</p>`,22)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};